mapper.select:
SELECT t.attr as attr, t.data as data, t.dsc as dsc, t.nums as nums, t.price as price, t.tat as tat, t.total as total, t.tpt as tpt, t.unit as unit, t.warehouse as warehouse, t.name as name, t.customer as customer, t.time as time, t.number as number, t.type as type FROM ( -- 1. 销售出库（type = 1） SELECT sori.attr, sori.data, sori.dsc, sori.nums, sori.price, sori.tat, sori.total, sori.tpt, sori.unit, sori.warehouse, g.name AS name, sor.customer, sor.time, sor.number, 1 AS type FROM sor_info sori LEFT JOIN goods g ON sori.goods = g.id LEFT JOIN sor ON sori.pid = sor.id
AND sor.time >= #{query.startTime}
AND sor.time <= #{query.endTime}
AND sor.customer = #{query.customer}
AND sor.number LIKE CONCAT('%', #{query.number}, '%')
AND sori.warehouse = #{query.warehouse}
AND g.name LIKE CONCAT('%', #{query.name}, '%')
AND sori.data LIKE CONCAT('%', #{query.data}, '%')
UNION ALL
-- 2. 销售退货（type = 0） SELECT srei.attr, srei.data, srei.dsc, srei.nums, srei.price, srei.tat, srei.total, srei.tpt, srei.unit, srei.warehouse, g.name AS name, sre.customer, sre.time, sre.number, 0 AS type FROM sre_info srei LEFT JOIN goods g ON srei.goods = g.id LEFT JOIN sre ON srei.pid = sre.id
AND sre.time >= #{query.startTime}
AND sre.time <= #{query.endTime}
AND sre.customer = #{query.customer}
AND sre.number LIKE CONCAT('%', #{query.number}, '%')
AND srei.warehouse = #{query.warehouse}
AND g.name LIKE CONCAT('%', #{query.name}, '%')
AND srei.data LIKE CONCAT('%', #{query.data}, '%')
) t
AND t.type = #{query.type}
ORDER BY t.time DESC

